// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/app-info", wrapper.GetAppInfo)
	router.POST(baseURL+"/attachments", wrapper.PostAttachment)
	router.DELETE(baseURL+"/attachments/:attachmentId", wrapper.DeleteAttachmentById)
	router.GET(baseURL+"/attachments/:attachmentId", wrapper.GetAttachmentById)
	router.PATCH(baseURL+"/attachments/:attachmentId", wrapper.PatchAttachmentById)
	router.GET(baseURL+"/attachments/:attachmentId/content", wrapper.GetAttachmentContent)
	router.PUT(baseURL+"/attachments/:attachmentId/content", wrapper.PutAttachmentContentById)
	router.POST(baseURL+"/attributes", wrapper.PostAttribute)
	router.DELETE(baseURL+"/attributes/:attributeId", wrapper.DeleteAttributeById)
	router.GET(baseURL+"/attributes/:attributeId", wrapper.GetAttributeById)
	router.PATCH(baseURL+"/attributes/:attributeId", wrapper.PatchAttributeById)
	router.POST(baseURL+"/auth/login", wrapper.Login)
	router.POST(baseURL+"/auth/logout", wrapper.Logout)
	router.PUT(baseURL+"/backup/:backupName", wrapper.CreateBackup)
	router.POST(baseURL+"/branches", wrapper.PostBranch)
	router.DELETE(baseURL+"/branches/:branchId", wrapper.DeleteBranchById)
	router.GET(baseURL+"/branches/:branchId", wrapper.GetBranchById)
	router.PATCH(baseURL+"/branches/:branchId", wrapper.PatchBranchById)
	router.GET(baseURL+"/calendar/days/:date", wrapper.GetDayNote)
	router.GET(baseURL+"/calendar/months/:month", wrapper.GetMonthNote)
	router.GET(baseURL+"/calendar/weeks/:date", wrapper.GetWeekFirstDayNote)
	router.GET(baseURL+"/calendar/years/:year", wrapper.GetYearNote)
	router.POST(baseURL+"/create-note", wrapper.CreateNote)
	router.GET(baseURL+"/inbox/:date", wrapper.GetInboxNote)
	router.GET(baseURL+"/notes", wrapper.SearchNotes)
	router.DELETE(baseURL+"/notes/:noteId", wrapper.DeleteNoteById)
	router.GET(baseURL+"/notes/:noteId", wrapper.GetNoteById)
	router.PATCH(baseURL+"/notes/:noteId", wrapper.PatchNoteById)
	router.GET(baseURL+"/notes/:noteId/content", wrapper.GetNoteContent)
	router.PUT(baseURL+"/notes/:noteId/content", wrapper.PutNoteContentById)
	router.GET(baseURL+"/notes/:noteId/export", wrapper.ExportNoteSubtree)
	router.POST(baseURL+"/notes/:noteId/import", wrapper.ImportZip)
	router.POST(baseURL+"/notes/:noteId/revision", wrapper.CreateRevision)
	router.POST(baseURL+"/refresh-note-ordering/:parentNoteId", wrapper.PostRefreshNoteOrdering)

}

